noncompliant:
// Multiple loop counters
for (int i = 0, j = 10; i < 5; ++i, --j) { // Noncompliant: multiple counters
    // loop body
}

// Floating point counter
for (double d = 0.0; d < 1.0; d += 0.1) { // Noncompliant: floating point counter
    // loop body
}

// Mixed types
for (int i = 0, char c = 'a'; i < 10; ++i, ++c) { // Noncompliant: mixed types
    // loop body
}

compliant:
// Single integer counter
for (int i = 0; i < 10; ++i) { // Compliant: single integer counter
    // loop body
}

// Using size_t for array iteration
for (size_t i = 0; i < array_size; ++i) { // Compliant: single size_t counter
    array[i] = 0;
}

// If multiple variables needed, declare outside
int i, j;
for (i = 0, j = 10; i < 5; ++i) { // Compliant: single loop counter
    j = j - 1; // Other variable modified in body
}
